@app.route('/')
def index():
    # Send user to authorization endpoint with client_id, redirect_uri, scope=openid, and response_type=id_token
    params = {
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'scope': 'openid',
        'response_type': 'id_token'
    }
    return redirect(f'{auth_url}?{requests.utils.urlencode(params)}')

